// --- Dish Classifier の output(JSON文字列) をパース ---
let parsed = {};
try {
  parsed = JSON.parse($json.output || '{}');
} catch (e) {
  parsed = {};
}

// --- カテゴリ取得 ---
const raw = parsed.category || '';
const top = raw.split('/')[0].trim(); // "中華" のように先頭部分を抽出

// --- マッピング定義 ---
const mapping = {
  '和食':    { type: 'restaurant', keyword: '和食 定食 そば うどん' },
  '洋食':    { type: 'restaurant', keyword: '洋食 ビストロ パスタ ハンバーグ' },
  '中華':    { type: 'restaurant', keyword: '中華 ラーメン 餃子 チャーハン' },
  'ラーメン': { type: 'restaurant', keyword: 'ラーメン つけ麺 中華そば' },
  '寿司':    { type: 'restaurant', keyword: '寿司 すし 魚介' },
  'カレー':  { type: 'restaurant', keyword: 'カレー スパイス インド料理' },
  'デザート': { type: 'cafe', keyword: 'スイーツ ケーキ パフェ デザート' }
};

// --- マッピング適用 ---
const conf = mapping[top] || { type: 'restaurant', keyword: top || 'レストラン' };

// --- 出力 ---
return {
  json: {
    dish_name: parsed.dish_name || '不明',
    category: top || '未分類',
    confidence: parsed.confidence || 0,
    ...conf
  }
};

