// Google Places の出力から必要な情報だけ抽出
const places = $json.places.map(p => ({
  name: p.displayName?.text || "不明",
  rating: p.rating || 0,
  reviews: p.userRatingCount || 0,
  address: p.shortFormattedAddress || "住所不明"
}));

// AIに渡すための簡潔なリスト文字列を生成
const summary = places.map(
  p => `${p.name}（評価: ${p.rating}, レビュー数: ${p.reviews}, 住所: ${p.address}）`
).join("\n");

return {
  json: {
    places,
    summary
  }
};

// AI Agentの出力（文字列）を取得
const raw = $json.output || "";

// JSONを安全にパース
let parsed = {};
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {};
}

// フィールドを明示的に整形
return {
  best_place: parsed.best_place || "",
  reason: parsed.reason || "",
};

// 1) AI出力を拾う（すでにオブジェクトならそれを使う）
let raw = $json.output ?? $json.data ?? $json.text ?? $json;
let parsed = {};

// 2) 文字列なら前後の余分を除去＆```jsonフェンスを剥がす
if (typeof raw === 'string') {
  let s = raw.trim();
  s = s.replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();
  try {
    parsed = JSON.parse(s);
  } catch {
    parsed = {};
  }
} else if (typeof raw === 'object') {
  parsed = raw;
}

// 3) 最低限のキーを用意（空でも構造は作る）
parsed.recommended_book = parsed.recommended_book || {};
parsed.recommended_book.title = parsed.recommended_book.title || '';
parsed.recommended_book.author = parsed.recommended_book.author || '';
parsed.reason = parsed.reason || '';
parsed.restaurant = parsed.restaurant || '';

return parsed;

// 「Get many volumes」ノードの 1 出力目(run 0 / output 0)の配列を取得
const vols = $items("Search Google Books", 0, 0);

// アイテムがなければ空で返す
if (!vols || vols.length === 0) {
  return [{ json: { title: "（タイトル不明）" } }];
}

// 先頭の本だけ使う（必要なら任意の選び方に変更）
const v = vols[0].json || {};
const vi = v.volumeInfo || {};

return [
  {
    json: {
      title: vi.title ?? "（タイトル不明）",
      authors: Array.isArray(vi.authors) ? vi.authors.join(", ") : "（著者情報なし）",
      publisher: vi.publisher ?? "（出版社不明）",
      publishedDate: vi.publishedDate ?? "―",
      selfLink: v.selfLink ?? ""
    }
  }
];

